import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Vertrauenswürdige Mods finden","description":"Eine Anleitung, wie man Fabric-Mods in vertrauenswürdigen Quellen findet.","frontmatter":{"title":"Vertrauenswürdige Mods finden","description":"Eine Anleitung, wie man Fabric-Mods in vertrauenswürdigen Quellen findet.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"de_de/players/finding-mods.md","filePath":"translated/de_de/players/finding-mods.md","lastUpdated":1770561656000}`);var a={name:`de_de/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Vertrauenswürdige Mods finden <a class="header-anchor" href="#h1" aria-label="Permalink to “Vertrauenswürdige Mods finden”">​</a></h1><p>Zu Beginn, Vertrauen ist subjektiv, du solltest beim Herunterladen von Mods immer nach eigenem Ermessen handeln. Hier sind ein paar Dinge, die dir helfen können, vertrauenswürdige Mods zu finden.</p><h2 id="trustworthy-source" tabindex="-1">1. Nutze eine Quelle, die bekanntermaßen vertrauenswürdig ist <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. Nutze eine Quelle, die bekanntermaßen vertrauenswürdig ist”">​</a></h2><p>Die meisten Autoren veröffentlichen ihre Mods auf <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> und <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Diese Webseiten prüfen, dass die Mods tun, was sie versprechen und, dass sie keinen bösartigen Code enthalten. Du kannst auf diesen Webseiten auch bösartige Mods melden, und sie werden ziemlich schnell Maßnahmen ergreifen.</p><h2 id="with-others" tabindex="-1">2. Frage bei Anderen nach! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Frage bei Anderen nach!”">​</a></h2><p>Wenn du eine Mod von einer nicht bekanntermaßen vertrauenswürdigen Quelle herunterlädst, solltest du bei Anderen nachfragen, um zu prüfen, ob sie die Mod vorher von der gleichen Seite heruntergeladen haben und ob sie Probleme damit hatten.</p><p>Frag im Zweifel gerne im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> nach.</p><h2 id="avoid-malware" tabindex="-1">3. Vermeide bekannte Schadware-Seiten! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Vermeide bekannte Schadware-Seiten!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Schadware-Seiten sind nicht für jeden offensichtlich. Falls du dir unsicher bist, solltest du dich nach Meinungen Anderer erkunden, oder die Seite meiden und dich nur auf vertrauenswürdige Quellen verlassen, wie Modrinth und CurseForge.</p></div><p>Es gibt viele Webseiten, die behaupten, sie hätten Mods für Minecraft, obwohl sie in Wirklichkeit nur Schadware-Seiten sind. Diese Seiten solltest du in jedem Fall vermeiden.</p><p>Du kannst Antiviren-Software und Webseiten wie <a href="https://www.microsoft.com/en-us/windows/windows-defender" target="_blank" rel="noreferrer">Windows Defender</a> oder <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> nutzen, um heruntergeladene Mods zu überprüfen. Verlass dich aber nicht vollständig auf diese Methoden, da sie manchmal falsche Ergebnisse liefern.</p><p>Nochmal, frag im Zweifel gerne im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> nach der Meinung Anderer.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};